exports.config = {
  headed: false,
  slowMo: 0,
};

exports.run = async ({ browser, context, page, result, helpers }) => {
  const BASE = 'https://agent-arena-roan.vercel.app';
  const results = [];
  const errors = [];
  const screenshots = [];

  const check = (label, pass, detail = '') => {
    results.push({ label, pass, detail });
    if (!pass) errors.push(`FAIL: ${label}${detail ? ' — ' + detail : ''}`);
  };

  const snap = async (name) => {
    const path = `/tmp/sentinel-screenshots/${name}.png`;
    await page.screenshot({ path, fullPage: false });
    screenshots.push(path);
  };

  // ─── SECTION 1: Public Route Health ──────────────────────────────────────────
  const publicRoutes = [
    '/',
    '/challenges',
    '/leaderboard',
    '/how-it-works',
    '/fair-play',
    '/philosophy',
    '/status',
    '/judging',
    '/docs/connector',
    '/docs/api',
    '/legal/terms',
    '/legal/privacy',
    '/legal/contest-rules',
    '/legal/responsible-gaming',
  ];

  for (const route of publicRoutes) {
    try {
      const response = await page.goto(BASE + route, { waitUntil: 'domcontentloaded', timeout: 20000 });
      const status = response ? response.status() : 0;
      const body = await page.content();
      const hasDBError = body.includes('PostgresError') || body.includes('syntax error') || body.includes('Error:') && body.includes('stack');
      const has500 = body.includes('500') && body.includes('Internal Server Error');
      check(`Public route ${route} returns 2xx`, status >= 200 && status < 400, `status=${status}`);
      check(`Public route ${route} no DB error`, !hasDBError, hasDBError ? 'DB error in page' : '');
      check(`Public route ${route} no 500`, !has500, has500 ? '500 visible in page' : '');
    } catch (e) {
      check(`Public route ${route} loads`, false, e.message);
    }
  }
  await snap('01-homepage');

  // ─── SECTION 2: /qa-login security check ─────────────────────────────────────
  try {
    const resp = await page.goto(BASE + '/qa-login', { waitUntil: 'domcontentloaded', timeout: 15000 });
    const status = resp ? resp.status() : 0;
    check('/qa-login returns 404 (not accessible in prod)', status === 404, `got ${status}`);
  } catch (e) {
    check('/qa-login returns 404', false, e.message);
  }

  // ─── SECTION 3: Auth redirect checks ─────────────────────────────────────────
  const authProtectedRoutes = ['/dashboard', '/dashboard/agents', '/dashboard/results', '/dashboard/wallet', '/admin', '/admin/challenges'];
  for (const route of authProtectedRoutes) {
    try {
      await page.goto(BASE + route, { waitUntil: 'domcontentloaded', timeout: 15000 });
      const url = page.url();
      const redirectedToLogin = url.includes('/login') || url.includes('/auth');
      check(`${route} redirects unauthenticated to login`, redirectedToLogin, `landed on ${url}`);
    } catch (e) {
      check(`${route} redirect`, false, e.message);
    }
  }
  await snap('02-auth-redirect');

  // ─── SECTION 4: API Health Checks ────────────────────────────────────────────
  const apis = [
    { path: '/api/health', expectKey: 'status' },
    { path: '/api/challenges?limit=5', expectKey: null },
    { path: '/api/leaderboard?limit=5', expectKey: null },
    { path: '/api/me', expectStatus: 401 },
  ];

  for (const api of apis) {
    try {
      const resp = await page.goto(BASE + api.path, { waitUntil: 'domcontentloaded', timeout: 15000 });
      const status = resp ? resp.status() : 0;
      if (api.expectStatus) {
        check(`API ${api.path} returns ${api.expectStatus}`, status === api.expectStatus, `got ${status}`);
      } else {
        check(`API ${api.path} returns 2xx`, status >= 200 && status < 400, `got ${status}`);
      }
      if (api.expectKey) {
        const body = await page.content();
        check(`API ${api.path} has key '${api.expectKey}'`, body.includes(api.expectKey), '');
      }
    } catch (e) {
      check(`API ${api.path}`, false, e.message);
    }
  }

  // ─── SECTION 5: Admin API access control ─────────────────────────────────────
  const adminApis = ['/api/admin/challenges', '/api/admin/forge-review', '/api/admin/inventory'];
  for (const api of adminApis) {
    try {
      const resp = await page.goto(BASE + api, { waitUntil: 'domcontentloaded', timeout: 15000 });
      const status = resp ? resp.status() : 0;
      check(`Admin API ${api} blocked for unauthed (401/403)`, status === 401 || status === 403, `got ${status}`);
    } catch (e) {
      check(`Admin API ${api} access control`, false, e.message);
    }
  }

  // ─── SECTION 6: Login flow (authenticate as QA admin) ────────────────────────
  try {
    await page.goto(BASE + '/login', { waitUntil: 'domcontentloaded', timeout: 15000 });
    await snap('03-login-page');

    // Fill login form
    await page.fill('input[type="email"], input[name="email"]', 'qa-bouts-001@mailinator.com');
    await page.fill('input[type="password"], input[name="password"]', 'BoutsQA2026!');
    await page.click('button[type="submit"]');
    await page.waitForNavigation({ timeout: 15000 }).catch(() => {});
    await page.waitForTimeout(3000);

    const urlAfterLogin = page.url();
    const loginSucceeded = !urlAfterLogin.includes('/login');
    check('Login flow succeeds for QA admin', loginSucceeded, `landed on ${urlAfterLogin}`);
    await snap('04-after-login');

    if (loginSucceeded) {
      // ─── SECTION 7: Authenticated routes (admin) ────────────────────────────────
      const authedRoutes = [
        '/dashboard',
        '/dashboard/agents',
        '/dashboard/results',
        '/dashboard/wallet',
        '/admin',
        '/admin/challenges',
      ];

      for (const route of authedRoutes) {
        try {
          const resp = await page.goto(BASE + route, { waitUntil: 'domcontentloaded', timeout: 15000 });
          const status = resp ? resp.status() : 0;
          const body = await page.content();
          const hasError = body.includes('PostgresError') || (body.includes('Error:') && body.includes('stack trace'));
          check(`Authed route ${route} loads (2xx)`, status >= 200 && status < 400, `got ${status}`);
          check(`Authed route ${route} no DB error`, !hasError, hasError ? 'DB error visible' : '');
        } catch (e) {
          check(`Authed route ${route}`, false, e.message);
        }
      }
      await snap('05-admin-challenges');

      // ─── SECTION 8: A3 fix — submission feedback polling (post-match breakdown) ─
      // Check /dashboard/results for real data and no spinner dead-end
      await page.goto(BASE + '/dashboard/results', { waitUntil: 'domcontentloaded', timeout: 20000 });
      await page.waitForTimeout(3000);
      const resultsBody = await page.content();
      const hasInfiniteSpinner = (resultsBody.match(/loading/gi) || []).length > 5;
      const hasRealContent = resultsBody.includes('score') || resultsBody.includes('result') || resultsBody.includes('No results') || resultsBody.includes('empty');
      check('Dashboard/results: no infinite spinner state', !hasInfiniteSpinner, hasInfiniteSpinner ? 'Multiple "loading" indicators suggest dead-end' : '');
      check('Dashboard/results: renders real content or empty state', hasRealContent, '');
      await snap('06-dashboard-results');

      // ─── SECTION 9: A4 fix — check classic tab is default on results/replay ────
      // Check replay page if any replays exist
      await page.goto(BASE + '/replays', { waitUntil: 'domcontentloaded', timeout: 15000 });
      await page.waitForTimeout(2000);
      const replaysBody = await page.content();
      const hasReplayContent = replaysBody.includes('replay') || replaysBody.includes('Replay') || replaysBody.includes('No replays') || replaysBody.includes('empty');
      check('/replays page loads with content or empty state', hasReplayContent, '');
      await snap('07-replays');

      // ─── SECTION 10: B2 fix — infra fields not leaking in replay API ────────────
      const replayApiResp = await page.goto(BASE + '/api/replays?limit=3', { waitUntil: 'domcontentloaded', timeout: 15000 });
      const replayApiStatus = replayApiResp ? replayApiResp.status() : 0;
      const replayApiBody = await page.content();

      if (replayApiStatus === 200) {
        // Check that infra fields are not present
        const hasModelId = replayApiBody.includes('"model_id"');
        const hasLatencyMs = replayApiBody.includes('"latency_ms"');
        const hasIsFallback = replayApiBody.includes('"is_fallback"');
        check('Replay API: model_id not leaking', !hasModelId, hasModelId ? 'model_id found in public replay API' : '');
        check('Replay API: latency_ms not leaking', !hasLatencyMs, hasLatencyMs ? 'latency_ms found in public replay API' : '');
        check('Replay API: is_fallback not leaking', !hasIsFallback, hasIsFallback ? 'is_fallback found in public replay API' : '');
      } else {
        check('Replay API accessible for check', false, `status=${replayApiStatus}`);
      }

      // ─── SECTION 11: B3 fix — short_rationale not leaking to public ─────────────
      // Test public replay API response
      try {
        const publicReplayResp = await page.goto(BASE + '/api/replays?limit=1&public=true', { waitUntil: 'domcontentloaded', timeout: 15000 });
        const publicReplayBody = await page.content();
        const hasShortRationale = publicReplayBody.includes('"short_rationale"');
        // short_rationale should either not be present or be null for non-owner
        check('Public replay API: short_rationale not exposed to non-owner', !hasShortRationale, hasShortRationale ? 'short_rationale found in public replay API response' : '');
      } catch (e) {
        check('Public replay API short_rationale check', false, e.message);
      }

      // ─── SECTION 12: Admin forge-review accessible ────────────────────────────
      await page.goto(BASE + '/admin', { waitUntil: 'domcontentloaded', timeout: 15000 });
      await page.waitForTimeout(2000);
      const adminBody = await page.content();
      const hasAdminContent = adminBody.includes('admin') || adminBody.includes('Admin') || adminBody.includes('Challenge') || adminBody.includes('Forge');
      check('/admin loads real admin content (not blank)', hasAdminContent, '');
      await snap('08-admin-panel');

      // ─── SECTION 13: Challenge pipeline UI ────────────────────────────────────
      await page.goto(BASE + '/admin/challenges', { waitUntil: 'domcontentloaded', timeout: 15000 });
      await page.waitForTimeout(2000);
      const adminChallengesBody = await page.content();
      const has500Error = adminChallengesBody.includes('500') || adminChallengesBody.includes('Internal Server Error');
      const hasChallengeContent = adminChallengesBody.includes('challenge') || adminChallengesBody.includes('Challenge') || adminChallengesBody.includes('No challenge') || adminChallengesBody.includes('pipeline');
      check('/admin/challenges: no 500 error', !has500Error, has500Error ? '500 visible' : '');
      check('/admin/challenges: loads challenge content or empty state', hasChallengeContent, '');
      await snap('09-admin-challenges-panel');
    }

  } catch (e) {
    check('Login flow execution', false, e.message);
  }

  // ─── SECTION 14: Mobile responsive (390px) ────────────────────────────────────
  try {
    const mobileCtx = await browser.newContext({ viewport: { width: 390, height: 844 } });
    const mobilePage = await mobileCtx.newPage();
    await mobilePage.goto(BASE, { waitUntil: 'domcontentloaded', timeout: 15000 });
    await mobilePage.waitForTimeout(1000);
    await mobilePage.screenshot({ path: '/tmp/sentinel-screenshots/10-mobile-home.png' });

    // Check for horizontal scroll
    const hasHorizontalScroll = await mobilePage.evaluate(() => {
      return document.documentElement.scrollWidth > document.documentElement.clientWidth;
    });
    check('Homepage: no horizontal scroll on mobile (390px)', !hasHorizontalScroll, hasHorizontalScroll ? 'Horizontal scroll detected' : '');

    await mobilePage.goto(BASE + '/challenges', { waitUntil: 'domcontentloaded', timeout: 15000 });
    await mobilePage.screenshot({ path: '/tmp/sentinel-screenshots/11-mobile-challenges.png' });
    const challengesMobileScroll = await mobilePage.evaluate(() => {
      return document.documentElement.scrollWidth > document.documentElement.clientWidth;
    });
    check('/challenges: no horizontal scroll on mobile', !challengesMobileScroll, '');
    await mobileCtx.close();
  } catch (e) {
    check('Mobile responsive test', false, e.message);
  }

  // ─── SECTION 15: Compliance footer check ──────────────────────────────────────
  try {
    await page.goto(BASE, { waitUntil: 'domcontentloaded', timeout: 15000 });
    const footerContent = await page.content();
    const has18Plus = footerContent.includes('18+') || footerContent.includes('18 +');
    const hasRestrictedStates = footerContent.includes('WA') && footerContent.includes('AZ') && footerContent.includes('LA');
    const hasIowaLegal = footerContent.includes('Iowa') || footerContent.includes('99B') || footerContent.includes('skill-based');
    check('Footer: 18+ notice present', has18Plus, '');
    check('Footer: restricted states mentioned', hasRestrictedStates, '');
    check('Page: Iowa/skill-based legal language present', hasIowaLegal, '');
  } catch (e) {
    check('Compliance footer check', false, e.message);
  }

  // ─── SECTION 16: Challenge detail page ────────────────────────────────────────
  try {
    const chalResp = await page.goto(BASE + '/api/challenges?limit=1', { waitUntil: 'domcontentloaded', timeout: 15000 });
    const chalBody = await page.content();
    const jsonMatch = chalBody.match(/"id"\s*:\s*"([^"]+)"/);
    if (jsonMatch && jsonMatch[1]) {
      const chalId = jsonMatch[1];
      await page.goto(BASE + `/challenges/${chalId}`, { waitUntil: 'domcontentloaded', timeout: 15000 });
      await page.waitForTimeout(2000);
      const detailBody = await page.content();
      const has500 = detailBody.includes('Internal Server Error');
      check('Challenge detail page: no 500', !has500, has500 ? '500 on detail page' : '');
      await snap('12-challenge-detail');
    } else {
      check('Challenge detail page: challenges exist in DB', false, 'No challenge ID found from API');
    }
  } catch (e) {
    check('Challenge detail page', false, e.message);
  }

  // ─── FINAL RESULT ─────────────────────────────────────────────────────────────
  const passed = results.filter(r => r.pass).length;
  const failed = results.filter(r => !r.pass).length;

  result.ok = failed === 0;
  result.summary = `${passed} PASS / ${failed} FAIL`;
  result.checks = results;
  result.failures = errors;
  result.screenshots = screenshots;

  console.log(`\n===== SENTINEL VERIFICATION AUDIT =====`);
  console.log(`TOTAL: ${passed + failed} checks | PASS: ${passed} | FAIL: ${failed}`);
  console.log('');
  for (const r of results) {
    console.log(`${r.pass ? '✅' : '❌'} ${r.label}${r.detail ? ' — ' + r.detail : ''}`);
  }
  if (errors.length > 0) {
    console.log('\n----- FAILURES -----');
    errors.forEach(e => console.log(e));
  }
  console.log('\nScreenshots:', screenshots.join(', '));
};

