import json

path = '/data/.openclaw/agents/forge/sessions/78148cd0-7d72-40f0-9a01-610b85f10244.jsonl'
with open(path) as f:
    lines = f.readlines()

print(f'Total lines (turns): {len(lines)}')
print()

for i, line in enumerate(lines[:4]):
    try:
        obj = json.loads(line.strip())
        role = obj.get('role', '?')
        content = obj.get('content', [])
        ts = obj.get('timestamp', '')
        thinking = obj.get('thinking', '')

        print(f'--- Turn {i+1} | role={role} | timestamp={ts} ---')
        print(f'  Keys: {list(obj.keys())}')

        if thinking:
            print(f'  THINKING (first 200 chars): {str(thinking)[:200]}')

        if isinstance(content, list):
            for item in content[:2]:
                ctype = item.get('type', '?')
                if ctype == 'text':
                    print(f'  TEXT: {str(item.get(\"text\", \"\"))[:200]}')
                elif ctype == 'thinking':
                    print(f'  THINKING BLOCK: {str(item.get(\"thinking\", \"\"))[:200]}')
                elif ctype == 'tool_use' or ctype == 'toolCall':
                    print(f'  TOOL: {item.get(\"name\", \"?\")} args={str(item.get(\"arguments\", item.get(\"input\", \"\")))[:100]}')
                elif ctype == 'tool_result' or ctype == 'toolResult':
                    print(f'  TOOL_RESULT: {str(item.get(\"content\", \"\"))[:100]}')
        elif isinstance(content, str):
            print(f'  CONTENT: {content[:200]}')
        print()
    except Exception as e:
        print(f'Error: {e}')
"

