python3 -c "
import json

path = '/data/.openclaw/agents/clawexpert/sessions/1ff05405-b673-4278-8395-b8918c173860.jsonl'
with open(path) as f:
    lines = f.readlines()

# Look for thinking content blocks
thinking_found = False
for line in lines:
    try:
        obj = json.loads(line.strip())
        if obj.get('type') == 'message':
            msg = obj.get('message', {})
            content = msg.get('content', [])
            if isinstance(content, list):
                for c in content:
                    if c.get('type') == 'thinking' and c.get('thinking'):
                        print('=== THINKING BLOCK FOUND ===')
                        print(c.get('thinking','')[:500])
                        print()
                        thinking_found = True
                        break
        if thinking_found:
            break
    except: pass

if not thinking_found:
    print('No thinking blocks in this session (thinking was off)')

# Also check for sessions_send calls (agent-to-agent)
print()
print('=== AGENT-TO-AGENT CALLS (sessions_send) ===')
count = 0
for line in lines:
    try:
        obj = json.loads(line.strip())
        if obj.get('type') == 'message':
            msg = obj.get('message', {})
            content = msg.get('content', [])
            if isinstance(content, list):
                for c in content:
                    if c.get('type') in ('tool_use','toolCall'):
                        name = c.get('name','')
                        if 'sessions_send' in name or 'sessions_spawn' in name or 'agent' in name.lower():
                            args = c.get('input', c.get('arguments', {}))
                            print(f'TOOL: {name}')
                            print(f'  args: {json.dumps(args, indent=2)[:300]}')
                            count += 1
    except: pass
print(f'Total agent-to-agent calls found: {count}')
"
